import * as assert from "assert";
import { Transaction } from "../js/transaction.js";

// BitGoJS fixtures
const signedSendTx =
  "te6cckEBAgEAqQAB4YgBJAxo7vqHF++LJ4bC/kJ8A1uVRskrKlrKJZ8rIB0tF+gCadlSX+hPo2mmhZyi0p3zTVUYVRkcmrCm97cSUFSa2vzvCArM3APg+ww92r3IcklNjnzfKOgysJVQXiCvj9SAaU1NGLsotvRwAAAAMAAcAQBmQgAaRefBOjTi/hwqDjv+7I6nGj9WEAe3ls/rFuBEQvggr5zEtAAAAAAAAAAAAAAAAAAAdfZO7w==";

const signedNominatorTx =
  "";

const whalesDepositTx =
  "te6cckEBAgEAvAAB4YgAyB87FgBG4jQNUAYzcmw2aJG9QQeQmtOPGsRPvX+eMdwFf6OLyGMsPoPXNPLUqMoUZTIrdu2maNNUK52q+Wa0BJhNq9e/qHXYsF9xU5TYbOsZt1EBGJf1GpkumdgXj0/4CU1NGLtKFdHwAAAC4AAcAQCLYgB1+pVcebAdRSEKQ8zKKRktAqKEg15Pa7hExBg/I76/y6gSoF8gAAAAAAAAAAAAAAAAAAB7zR/vAAAAAGlCugJDuaygCErRw2Y=";

const tokenSendTx =
  "";

describe("Transaction", () => {
  it("should deserialize a send transaction from BOC", () => {
    const tx = Transaction.fromBoc(signedSendTx);
    assert.strictEqual(tx.seqno, 6);
    assert.strictEqual(tx.walletId, 698983191);
  });

  it("should get the correct transaction ID", () => {
    const tx = Transaction.fromBoc(signedSendTx);
    assert.strictEqual(tx.id, "tuyOkyFUMv_neV_FeNBH24Nd4cML2jUgDP4zjGkuOFI=");
  });

  it("should get the correct signable payload", () => {
    const tx = Transaction.fromBoc(signedSendTx);
    const payload = tx.signablePayload();
    const payloadB64 = Buffer.from(payload).toString("base64");
    assert.strictEqual(payloadB64, "k4XUmjB65j3klMXCXdh5Vs3bJZzo3NSfnXK8NIYFayI=");
  });

  it("should detect state init in nominator tx (seqno=0)", () => {
    const tx = Transaction.fromBoc(signedNominatorTx);
    assert.strictEqual(tx.seqno, 0);
    assert.strictEqual(tx.hasStateInit, true);
  });

  it("should get correct nominator tx ID", () => {
    const tx = Transaction.fromBoc(signedNominatorTx);
    assert.strictEqual(tx.id, "n1rr-QL61WZ7UJN7ESH2iPQO7toTy9WLqXoSIG1JtXg=");
  });

  it("should roundtrip through broadcast format", () => {
    const tx = Transaction.fromBoc(signedSendTx);
    const broadcast = tx.toBroadcastFormat();
    const tx2 = Transaction.fromBoc(broadcast);
    assert.strictEqual(tx2.seqno, tx.seqno);
    assert.strictEqual(tx2.walletId, tx.walletId);
    assert.strictEqual(tx2.id, tx.id);
  });

  it("should parse whales deposit tx", () => {
    const tx = Transaction.fromBoc(whalesDepositTx);
    assert.strictEqual(tx.seqno, 92);
  });

  it("should parse token send tx", () => {
    const tx = Transaction.fromBoc(tokenSendTx);
    assert.strictEqual(tx.seqno, 0);
    assert.strictEqual(tx.hasStateInit, true);
  });

  it("should serialize to bytes", () => {
    const tx = Transaction.fromBoc(signedSendTx);
    const bytes = tx.toBytes();
    assert.ok(bytes.length > 0);
  });
});
